const oauthClient = {
    tokenEndpoint: 'https://your-auth-server.com/token', // Replace with your token endpoint
    clientId: 'your-client-id',
    clientSecret: 'your-client-secret',
    accessTokenKey: 'accessToken',
    refreshTokenKey: 'refreshToken',
    tokenExpiryKey: 'tokenExpiry',

    async getAccessToken() {
        const now = Date.now();
        const expiry = localStorage.getItem(this.tokenExpiryKey);

        if (expiry && now < expiry) {
            return localStorage.getItem(this.accessTokenKey);
        }

        return await this.refreshAccessToken();
    },

    async refreshAccessToken() {
        const refreshToken = localStorage.getItem(this.refreshTokenKey);
        if (!refreshToken) {
            throw new Error('No refresh token available');
        }

        const response = await fetch(this.tokenEndpoint, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded',
            },
            body: new URLSearchParams({
                grant_type: 'refresh_token',
                refresh_token: refreshToken,
                client_id: this.clientId,
                client_secret: this.clientSecret
            })
        });

        if (!response.ok) {
            throw new Error('Failed to refresh access token');
        }

        const data = await response.json();
        this.storeTokens(data);
        return data.access_token;
    },

    storeTokens(data) {
        const now = Date.now();
        const expiry = now + data.expires_in * 1000; // convert seconds to milliseconds

        localStorage.setItem(this.accessTokenKey, data.access_token);
        localStorage.setItem(this.refreshTokenKey, data.refresh_token);
        localStorage.setItem(this.tokenExpiryKey, expiry);
    },

    async authenticate(username, password) {
        const response = await fetch(this.tokenEndpoint, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded',
            },
            body: new URLSearchParams({
                grant_type: 'password',
                username: username,
                password: password,
                client_id: this.clientId,
                client_secret: this.clientSecret
            })
        });

        if (!response.ok) {
            throw new Error('Authentication failed');
        }

        const data = await response.json();
        this.storeTokens(data);
    }
};

